tools.description_and_exact_tool_declaration:
This endpoint provides aggregated metrics for mentions of the keywords or domains specified in the target array of the request.

exec tool declaration:
```ts
declare const tools: { mcp__dataforseo__ai_opt_llm_ment_agg_metrics(args: {
  // Array-based filter expression. A single condition is a 3-element array: [field, operator, value]. Combine conditions with ["and"|"or"] between them: [condition, "and", condition]. Max 8 filters.
  // Operators: regex, not_regex, <, <=, >, >=, =, <>, in, not_in, match, not_match, ilike, not_ilike, like, not_like
  // Use % with like/not_like/ilike/not_ilike as a wildcard.
  // Example:
  // Single: ["ai_search_volume", ">", "1000"]
  // The full list of possible filters is available in 'ai_optimization_llm_mentions_filters' tool
  filters?: Array<Array<string | number | boolean> | "and" | "or" | Array<unknown> | string | number | unknown | unknown>;
  // Internal parameter to limit the number of items processed. Not exposed to end-users.
  internal_list_limit?: number;
  // Search engine language code (e.g., 'en')
  language_code?: string;
  // full name of the location, example: 'United Kingdom', 'United States'
  location_name?: string;
  // Platform to search for LLM mentions
  platform?: "chat_gpt" | "google";
  // Array of target objects to search for LLM mentions. Each object must contain either 'domain' or 'keyword'. Maximum number of targets: 1000
  target: Array<{
  // Target domain to search for LLM mentions
  domain: string;
  // Search filter to apply (include or exclude)
  search_filter?: "include" | "exclude";
  // Target search scope for LLM mentions
  search_scope?: Array<"any" | "question" | "answer">;
} | {
  // Target keyword to search for LLM mentions
  keyword: string;
  // Match type for the keyword
  match_type?: "word_match" | "partial_match";
  // Search filter to apply (include or exclude)
  search_filter?: "include" | "exclude";
  // Target search scope for LLM mentions
  search_scope?: Array<"any" | "question" | "answer">;
}>;
}): Promise<CallToolResult>; };
```

